#include<bits/stdc++.h>
using namespace std;
int a[1001][1001];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            char ch;
            cin>>ch;
            if(ch=='L')
            {
                a[i][j]=0;
            }
            else
            {
                a[i][j]=1;
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(a[1][i]==1)
        {
            for(int j=1;j<=n;j++)
            {
                a[j][i]=!a[j][i];
            }
        }
        if(a[i][1]==1)
        {
            for(int j=1;j<=n;j++)
            {
                a[i][j]=!a[i][j];
            }
        }
    }
    int cnt1=0;
    for(int i=2;i<=n;i++)
    {
        for(int j=2;j<=n;j++)
        {
            if(a[i][j])
            {
                cnt1++;
            }
        }
    }
    if(cnt1==(n-1)*(n-1))
    {
        printf("1 1");
        return 0;
    }
    int tx,ty,tx1=0,ty1=0,cnt=0;
    for(int i=2;i<=n;i++)
    {
        for(int j=2;j<=n;j++)
        {
            if(a[i][j])
            {
                cnt++;
                if(cnt>1&&(i!=tx&&j!=ty))
                {
                    printf("-1");
                    return 0;
                }
                if(cnt>1&&i==tx)
                {
                    tx1=1;
                }
                if(cnt>1&&j==ty)
                {
                    ty1=1;
                }
                tx=i;
                ty=j;
            }
        }
    }
    if(cnt==1)
    {
        printf("%d %d",tx,ty);
    }
    else if(cnt==n-1&&tx1==1)
    {
        printf("%d 1",tx);
    }
    else if(cnt==n-1&&ty1==1)
    {
        printf("1 %d",ty);
    }
    else
    {
        printf("-1");
    }
    return 0;
}
